CREATE TABLE `job_posts` (
  `id` int NOT NULL AUTO_INCREMENT,
  `title` varchar(200) NOT NULL,
  `company` varchar(150) NOT NULL,
  `location` varchar(150) NOT NULL,
  `job_type` enum('Full-time','Part-time','Contract','Internship','Freelance') NOT NULL,
  `work_mode` enum('On-site','Remote','Hybrid') DEFAULT 'On-site',
  `experience_level` enum('Fresher','Junior','Mid-level','Senior') DEFAULT 'Fresher',
  `job_industry` enum('IT','Finance','Healthcare','Education','Other') NOT NULL DEFAULT 'Other',
  `description` text NOT NULL,
  `requirements` text NOT NULL,
  `salary` varchar(100) NOT NULL,
  `posted_by` int NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=73 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
