INSERT INTO `job_posts` VALUES (1,'Software Engineer','TechNova Solutions','Yangon, Myanmar','Full-time','Hybrid','Fresher','Other','Join our engineering team to design and implement scalable software solutions for enterprise clients. You will contribute to the full development cycle, from coding and testing to deployment and maintenance. As a fresher, you will be mentored by senior engineers and learn best practices in agile development.','- Bachelor’s degree in Computer Science or related field\n- Familiarity with at least one programming language (Java, Python, C#)\n- Understanding of databases and version control (Git)\n- Problem-solving and analytical mindset\n- Strong willingness to learn and adapt','$1500.00/month',1,'2025-08-15 21:43:27','2025-08-23 00:07:11'),(2,'Junior 3D Artist','PixelForge Studios','Remote','Full-time','Remote','Junior','Other','Work closely with senior artists to create 3D assets for Unreal Engine projects. You will learn the end-to-end pipeline including modeling, texturing, and integration. This role is ideal for candidates looking to grow into a full production artist role.','- Basic skills in Blender, Maya, or 3ds Max\n- Understanding of UVs and PBR workflows\n- Portfolio with at least 2–3 completed projects\n- Enthusiastic about games and digital art\n- Ability to follow feedback and iterate quickly','$2,500/month',0,'2025-08-15 22:38:56','2025-08-23 00:07:11'),(5,'Burmese Language Specialist','Firstsource','Remote','Part-time','Remote','Senior','Other','Provide translation, localization, and linguistic QA for Burmese-language content across customer service and business documents. Collaborate with global teams to ensure cultural accuracy and clarity in communication.','- Native or fluent Burmese speaker with excellent written skills\n- Strong English communication abilities\n- Experience in translation/localization preferred\n- Familiarity with CAT tools is a plus\n- Attention to detail and cultural sensitivity','$4000/month',2,'2025-08-16 03:23:25','2025-08-23 00:07:11'),(6,'Behavioral Health Coach','Intellect','Yangon,Myanmar','Contract','On-site','Senior','Healthcare','Work with clients to provide mental health coaching and wellness strategies. You will facilitate one-on-one sessions, support behavioral change, and help clients set achievable goals in a structured program.','- Certification in counseling, psychology, or coaching\n- 3–5 years relevant experience in mental health support\n- Empathetic listener with strong interpersonal skills\n- Ability to maintain confidentiality and professionalism\n- Comfortable working on-site with diverse clients','$4000/month',2,'2025-08-16 03:25:42','2025-08-23 00:07:11'),(7,'Backend Software Engineer','Innovatech Ltd','New York, USA','Internship','Hybrid','Mid-level','IT','Design and maintain backend services for enterprise systems. You will build APIs, optimize database performance, and collaborate with frontend teams to deliver seamless applications.','- Proficiency in Java, Python, or Node.js\n- Experience with REST APIs and relational databases\n- Familiarity with cloud platforms (AWS/Azure)\n- Strong debugging and problem-solving skills\n- Internship or project experience in backend development','$90,000 - $115,000',1,'2025-08-20 21:06:14','2025-08-23 00:07:11'),(8,'Financial Analyst','Global Finance Corp','London, UK','Full-time','Hybrid','Mid-level','Finance','Support financial planning and decision-making by preparing models, analyzing market trends, and delivering insights to stakeholders. Collaborate with senior analysts to evaluate performance and forecast budgets.','- Bachelor’s in Finance, Economics, or related field\n- Strong Excel and financial modeling skills\n- Analytical mindset and attention to detail\n- Experience with Power BI/Tableau preferred\n- Excellent communication skills','£48,000 - £60,000',2,'2025-08-20 21:06:14','2025-08-23 00:07:11'),(9,'Healthcare Recruiter','MediConnect','Los Angeles, USA','Full-time','On-site','Junior','Healthcare','Manage full-cycle recruitment for healthcare roles, including sourcing, screening, interviewing, and onboarding. Build strong relationships with hiring managers and ensure candidates have a positive experience.','- 1–3 years recruitment experience\n- Familiarity with healthcare job roles and certifications\n- Strong sourcing and networking skills\n- ATS proficiency\n- Excellent communication and relationship-building abilities','$58,000 - $70,000 + commission',3,'2025-08-20 21:06:14','2025-08-23 00:07:11'),(10,'Education Program Coordinator','Bright Future Schools','Madrid, Spain','Full-time','On-site','Junior','Education','Coordinate educational programs, ensuring curriculum delivery, scheduling, and student support. You will collaborate with teachers and administrators to improve program outcomes.','- Bachelor’s degree in Education or related field\n- Organizational and multitasking skills\n- Experience in academic coordination preferred\n- Strong communication and teamwork skills\n- Ability to work on-site with staff and students','€28,000 - €34,000',4,'2025-08-20 21:06:14','2025-08-23 00:07:11'),(11,'IT Operations Manager','Apex Solutions','Austin, USA','Full-time','On-site','Senior','IT','Oversee IT infrastructure and operations, ensuring system reliability, security, and scalability. Lead a team of IT specialists and collaborate with leadership to support business objectives.','- 8+ years IT operations experience\n- Strong knowledge of networks, servers, and security\n- Leadership and team management skills\n- Familiarity with ITIL frameworks\n- Excellent problem-solving and strategic thinking','$130,000 - $155,000 + bonus',5,'2025-08-20 21:06:14','2025-08-23 00:07:11'),(12,'Talent Acquisition Specialist','Euro Finance Group','Paris, France','Contract','Hybrid','Mid-level','Finance','Drive recruitment efforts for finance roles across Europe. You will source, interview, and manage offers while partnering with HR to support workforce planning.','- 3+ years recruitment or HR experience\n- Strong sourcing and interviewing skills\n- Familiarity with finance sector talent needs\n- Fluency in English and French preferred\n- Excellent negotiation and relationship-building','€55,000 - €65,000 (pro-rated)',6,'2025-08-20 21:06:14','2025-08-23 00:07:11'),(13,'Registered Nurse (ER)','HealthBridge Inc','Houston, USA','Full-time','On-site','Mid-level','Healthcare','Provide direct patient care in the emergency room, including triage, monitoring, and acute treatment. Work collaboratively with doctors and the healthcare team to deliver high-quality emergency services.','- Valid RN license (USA)\n- 2+ years ER or acute care experience\n- Strong knowledge of emergency protocols\n- Ability to work under pressure\n- Compassionate patient care and teamwork skills','$84,000 - $102,000 + differentials',7,'2025-08-20 21:06:14','2025-08-23 00:07:11'),(14,'Teacher Recruiter','EduWorld Foundation','Singapore','Full-time','Hybrid','Junior','Education','Recruit qualified teachers for international schools across Southeast Asia. You will manage hiring pipelines, attend career fairs, and collaborate with school leaders to meet staffing needs.','- 1–3 years recruitment experience\n- Familiarity with teacher certification requirements\n- Strong networking and communication skills\n- Event planning experience preferred\n- Ability to work in hybrid setups and travel occasionally','SGD 48,000 - 65,000',8,'2025-08-20 21:06:14','2025-08-23 00:07:11'),(15,'Business Analyst (Data)','BrightTech Solutions','San Diego, USA','Full-time','Hybrid','Mid-level','IT','Collaborate with business and engineering teams to analyze requirements, develop dashboards, and deliver insights that drive product decisions. Focus on data collection, cleaning, and visualization for stakeholders.','- 3+ years as Business/Data Analyst\n- SQL and data visualization (Tableau/Power BI)\n- Strong Excel and analytical skills\n- Excellent communication and documentation\n- Familiarity with SaaS and cloud-based data','$85,000 - $105,000',9,'2025-08-20 21:06:14','2025-08-23 00:07:11'),(16,'HR Consultant','FinGrowth Partners','Frankfurt, Germany','Contract','Remote','Senior','Finance','As an HR Consultant, you will partner with portfolio companies to design and implement scalable HR frameworks. You will focus on compensation strategies, performance management systems, and organizational design while advising leadership on people-related challenges. This is a highly autonomous role requiring strong problem-solving skills, business acumen, and the ability to deliver tailored solutions across multiple industries. \n\nYou will also lead workshops and training sessions, helping clients implement best practices in employee engagement, compliance, and talent management. Your work will directly influence company culture, retention, and long-term workforce planning.','- 7+ years of experience in HR consulting, HRBP, or organizational development\n- Deep expertise in compensation & benefits strategy\n- Strong track record of building scalable HR frameworks\n- Excellent stakeholder management and executive communication skills\n- Fluency in English; German is a strong advantage\n- Ability to manage multiple client engagements simultaneously\n- Willingness to travel up to 25% as required','€75,000 - €95,000 (annualized)',10,'2025-08-20 21:06:14','2025-08-23 00:11:24'),(17,'Healthcare Operations Manager','LifeCare Systems','San Jose, USA','Full-time','On-site','Senior','Healthcare','As a Healthcare Operations Manager, you will oversee daily clinical operations across multiple facilities, ensuring compliance with healthcare regulations and delivering high-quality patient care. You will manage budgets, vendor contracts, and staffing plans while building efficient workflows that support doctors, nurses, and administrative teams. \n\nIn this leadership role, you will identify gaps in service delivery, lead process improvements, and implement systems that enhance patient outcomes. You will collaborate closely with senior leadership to align operational goals with long-term business strategies.','- 5+ years of experience in healthcare operations or management\n- Strong knowledge of HIPAA, JCAHO, and healthcare compliance standards\n- Proven ability to manage budgets, contracts, and staffing\n- Familiarity with EMR systems (Epic or Cerner preferred)\n- Excellent organizational and leadership skills\n- Strong communication abilities with clinical and non-clinical staff\n- Ability to balance strategic planning with hands-on operational oversight','$110,000 - $135,000 + benefits',11,'2025-08-20 21:06:14','2025-08-23 00:11:24'),(18,'School HR Manager','Harmony Academy','Brooklyn, USA','Full-time','On-site','Mid-level','Education','As the School HR Manager, you will lead human resources operations for a growing K-12 charter school network. You will manage recruitment, onboarding, employee relations, and compliance while helping to foster a culture of inclusivity and professional growth. \n\nIn addition to managing HR policies and procedures, you will support school leaders in handling sensitive staff matters, building professional development programs, and maintaining compliance with US labor laws. This role requires empathy, strong organizational skills, and the ability to balance the needs of both staff and leadership.','- 3–5 years of HR management or HR generalist experience\n- Strong understanding of US labor laws and compliance requirements\n- Experience in school or non-profit settings preferred\n- Excellent conflict resolution and coaching skills\n- Ability to design and implement HR processes at scale\n- SHRM-CP, PHR, or equivalent certification preferred\n- Strong interpersonal skills with an inclusive leadership style','$72,000 - $88,000',12,'2025-08-20 21:06:14','2025-08-23 00:11:24'),(19,'Project Manager (Platforms)','TechGlobal Inc','Los Angeles, USA','Full-time','Hybrid','Mid-level','IT','As a Project Manager (Platforms), you will oversee delivery of core platform initiatives that enable multiple product teams across the company. You will own planning, risk management, stakeholder communication, and ensure smooth execution of cross-functional projects. \n\nYour responsibilities will include leading agile ceremonies, ensuring delivery timelines are met, and coordinating with engineering, design, and product stakeholders. This role requires technical fluency, excellent communication, and a proactive approach to problem solving.','- 4+ years of project or program management experience\n- Strong knowledge of Agile and Scrum methodologies\n- Proven track record of delivering complex cross-functional projects\n- Excellent risk and issue management skills\n- Familiarity with Jira, Confluence, or similar project tools\n- Strong stakeholder communication and presentation skills\n- Technical background or understanding of platform infrastructure preferred','$105,000 - $125,000 + bonus',13,'2025-08-20 21:06:14','2025-08-23 00:11:24'),(20,'Financial Planning Associate','Crescent Finance','Dubai, UAE','Full-time','On-site','Junior','Finance','As a Financial Planning Associate, you will work with wealth advisors to deliver financial plans and investment strategies for high-net-worth clients. You will prepare detailed plans, run scenario analysis, and assist in client onboarding and review sessions. \n\nThis role provides an excellent opportunity to develop expertise in wealth management, learn industry best practices, and build trusted relationships with clients while supporting senior financial planners.','- Bachelor’s degree in Finance, Economics, or a related field\n- Strong analytical and Excel modeling skills\n- Attention to detail and client-centric approach\n- Excellent written and verbal communication\n- Familiarity with wealth management tools and platforms is a plus\n- Ability to manage multiple projects under deadlines\n- Arabic or Hindi language skills are an advantage','AED 14,000 - 18,000 / month',14,'2025-08-20 21:06:14','2025-08-23 00:11:24'),(21,'Recruiter (Generalist)','NextGen Careers','Washington, USA','Full-time','Remote','Junior','Other','As a Recruiter (Generalist), you will manage full-cycle recruitment across industries such as technology, retail, and logistics. You will source, interview, and place candidates into roles while partnering with hiring managers to deliver top talent. \n\nThis role requires strong multitasking abilities, resilience in managing multiple job openings, and excellent interpersonal skills to build lasting relationships with both candidates and clients.','- 1–2 years of full-cycle recruitment experience\n- Strong sourcing and candidate engagement skills\n- Proficiency in applicant tracking systems (ATS)\n- Structured interviewing and assessment skills\n- Target-driven and resilient mindset\n- Excellent written and verbal English\n- Ability to manage 10–15 open roles simultaneously','$52,000 - $68,000 + commission',15,'2025-08-20 21:06:14','2025-08-23 00:11:24'),(23,'Data Engineer','Global Finance Corp','Manchester, UK','Full-time','Hybrid','Mid-level','Finance','As a Data Engineer, you will design, build, and optimize data pipelines that support trading and risk analytics functions. You will collaborate with stakeholders to define data models, maintain data quality, and deliver reliable ETL solutions. \n\nYou will also play a key role in improving data governance, enabling scalable analytics, and supporting regulatory reporting by building clean, well-documented, and auditable data workflows.','- 3+ years of experience as a Data Engineer\n- Strong Python and SQL development skills\n- Hands-on experience with ETL/ELT tools such as Airflow or DBT\n- Familiarity with cloud-based data warehouses (Snowflake, Redshift, BigQuery)\n- Experience with CI/CD and version control workflows\n- Knowledge of data governance, lineage, and security best practices\n- Excellent problem-solving and analytical mindset','£55,000 - £70,000',2,'2025-08-20 21:06:14','2025-08-23 00:11:24'),(24,'Clinical Data Manager','MediConnect','Phoenix, USA','Full-time','Hybrid','Senior','Healthcare','As a Clinical Data Manager, you will oversee the design, collection, and management of clinical trial data. You will define data standards, lead vendor management, and ensure compliance with ICH-GCP and other regulatory requirements. \n\nYou will also partner with clinical operations teams to improve data accuracy, implement EDC systems, and prepare clean datasets for statistical analysis and regulatory submission.','- 6+ years of experience in clinical data management\n- Proficiency with EDC systems (Medidata, REDCap, or similar)\n- Knowledge of SDTM and ADaM standards\n- Strong vendor management and timeline management skills\n- Excellent documentation and audit-readiness capabilities\n- Familiarity with FDA and EMA regulatory expectations\n- Strong communication and problem-solving skills','$120,000 - $145,000',3,'2025-08-20 21:06:14','2025-08-23 00:11:24'),(26,'Security Engineer (Blue Team)','Apex Solutions','Seattle, USA','Full-time','Hybrid','Senior','IT','As a Security Engineer on the Blue Team, you will strengthen the company’s security posture by detecting, responding to, and mitigating threats across cloud and on-premise environments. You will develop monitoring and detection rules, participate in incident response, and ensure secure-by-design practices with product teams. \n\nYou will also lead investigations of security events, perform root cause analysis, and recommend improvements to prevent recurrence. Collaboration with developers and infrastructure teams is crucial to embed security in every stage of the product lifecycle.','- 5+ years of experience in security engineering, SOC, or incident response\n- Proficiency with SIEM/EDR tools (Splunk, Sentinel, CrowdStrike)\n- Strong knowledge of threat modeling and secure coding practices\n- Hands-on cloud security expertise (AWS, Azure, or GCP)\n- Experience writing and tuning detection rules\n- On-call experience in high-availability environments\n- Excellent analytical and communication skills','$135,000 - $165,000',5,'2025-08-20 21:06:14','2025-08-23 00:13:34'),(27,'Compensation Analyst','Euro Finance Group','Lyon, France','Full-time','Hybrid','Junior','Finance','As a Compensation Analyst, you will support annual compensation reviews across multiple EU countries. You will benchmark salaries, analyze pay equity, and assist HRBPs with designing competitive compensation packages. \n\nThis role requires high attention to detail, strong data analysis skills, and the ability to interpret salary survey data while balancing local compliance considerations.','- 1–3 years of experience in HR analytics or compensation\n- Strong Excel and quantitative analysis skills\n- Understanding of European labor contexts and pay structures\n- Experience working with salary survey vendors preferred\n- Confidentiality and integrity in handling sensitive data\n- Excellent communication and stakeholder management skills\n- Proficiency in English; French or other EU language is a plus','€38,000 - €48,000',6,'2025-08-20 21:06:14','2025-08-23 00:13:34'),(28,'Physician Assistant (Primary Care)','HealthBridge Inc','Dallas, USA','Full-time','On-site','Mid-level','Healthcare','As a Physician Assistant in a primary care setting, you will provide compassionate, patient-centered healthcare including routine checkups, preventive care, and chronic condition management. You will work alongside physicians, nurses, and other healthcare professionals to deliver comprehensive treatment. \n\nYou will be expected to assess patients, order tests, and provide education on maintaining long-term health, always ensuring compliance with medical and safety standards.','- Valid PA license and NCCPA certification\n- 2+ years of experience in a primary care or outpatient clinic\n- Strong ability to build rapport with patients and families\n- Knowledge of preventative care and chronic disease management\n- Excellent charting and documentation skills\n- Familiarity with OSHA and vaccination protocols\n- Bilingual (Spanish/English) is strongly preferred','$105,000 - $125,000',7,'2025-08-20 21:06:14','2025-08-23 00:13:34'),(29,'University Partnerships Manager','EduWorld Foundation','Kuala Lumpur, Malaysia','Full-time','Hybrid','Mid-level','Education','As a University Partnerships Manager, you will establish and manage strategic relationships with universities across Southeast Asia to expand teacher pipelines. You will negotiate MOUs, design internship programs, and lead outreach efforts such as job fairs and workshops. \n\nYou will also coordinate with internal stakeholders to ensure alignment with organizational goals while monitoring the success and impact of each partnership.','- 4+ years of experience in partnerships, campus relations, or education outreach\n- Excellent negotiation and presentation skills\n- Strong ability to manage multiple stakeholders simultaneously\n- Data-driven mindset with reporting and tracking experience\n- Willingness to travel up to 30% across the region\n- Fluency in English; Bahasa or another SEA language is a plus\n- Strong organizational and follow-up skills','MYR 9,000 - 12,000 / month',8,'2025-08-20 21:06:14','2025-08-23 00:13:34'),(30,'Site Reliability Engineer','BrightTech Solutions','Denver, USA','Full-time','Hybrid','Mid-level','IT','As a Site Reliability Engineer, you will be responsible for ensuring the reliability, scalability, and performance of the company’s payments platform. You will develop observability systems, automate operational tasks, and work closely with developers to embed reliability into the software lifecycle. \n\nYou will also participate in incident response, postmortems, and capacity planning to continuously improve service availability and user experience.','- 3+ years of experience in SRE, DevOps, or systems engineering\n- Strong knowledge of cloud platforms (AWS, GCP, or Azure)\n- Proficiency in Linux administration and shell scripting\n- Experience with infrastructure-as-code (Terraform, Ansible)\n- Familiarity with monitoring/alerting tools (Prometheus, Grafana, etc.)\n- Solid incident response and root cause analysis experience\n- Strong communication and collaboration skills','$110,000 - $135,000',9,'2025-08-20 21:06:14','2025-08-23 00:13:34'),(31,'HR Business Partner','FinGrowth Partners','Munich, Germany','Full-time','Hybrid','Senior','Finance','As an HR Business Partner, you will act as a strategic advisor to fintech portfolio companies. You will support leadership in talent management, organizational design, employee engagement, and change management. \n\nYou will also develop and implement HR strategies that align with business goals while building trust with employees across all levels of the organization.','- 6+ years of experience as an HRBP or senior HR professional\n- Proven ability to support senior leaders and drive organizational change\n- Expertise in talent management, performance management, and ER cases\n- Strong communication and coaching skills\n- Experience working in high-growth or startup environments\n- Ability to balance strategic planning with operational execution\n- Fluency in English; German preferred','€85,000 - €105,000',10,'2025-08-20 21:06:14','2025-08-23 00:13:34'),(32,'Clinic Administrator','LifeCare Systems','Sacramento, USA','Full-time','On-site','Junior','Healthcare','As a Clinic Administrator, you will ensure smooth daily operations at a pediatrics clinic. You will oversee scheduling, patient communications, inventory management, and compliance with healthcare standards. \n\nYou will play a central role in ensuring patients and families receive excellent care by enabling physicians and nurses to operate efficiently and effectively.','- 1–3 years of experience in clinic administration or office management\n- Familiarity with EMR systems (Epic preferred)\n- Excellent organizational and multitasking abilities\n- Strong communication and customer service orientation\n- Ability to remain empathetic and professional with patients\n- Problem-solving mindset with proactive initiative\n- Bilingual ability (Spanish/English) is a plus','$54,000 - $62,000',11,'2025-08-20 21:06:14','2025-08-23 00:13:34'),(33,'People Operations Specialist','Harmony Academy','Queens, USA','Full-time','On-site','Junior','Education','As a People Operations Specialist, you will support HR operations across onboarding, payroll, benefits, and compliance for a growing school network. You will help streamline HR processes, improve employee experiences, and maintain accurate records. \n\nYou will also assist in scaling people operations as the organization grows, ensuring policies and systems adapt to the needs of staff and administrators.','- 1–3 years of experience in HR, People Ops, or administrative roles\n- Proficiency in HRIS and ATS tools\n- Strong attention to detail and confidentiality in handling records\n- Customer service mindset with staff support experience\n- Familiarity with school or non-profit environments preferred\n- Ability to manage multiple tasks under deadlines\n- Excellent written and verbal communication','$60,000 - $70,000',12,'2025-08-20 21:06:14','2025-08-23 00:13:34'),(34,'Senior QA Engineer','TechGlobal Inc','Seattle, USA','Full-time','Hybrid','Senior','IT','As a Senior QA Engineer, you will lead quality assurance efforts for platform integrations and critical software systems. You will design test strategies, automate key scenarios, and coach developers in implementing quality practices throughout the SDLC. \n\nYou will play a critical role in identifying risks, improving release reliability, and enhancing customer satisfaction through proactive testing and automation.','- 6+ years of QA or test automation experience\n- Strong proficiency in programming languages (Java, JavaScript, or Python)\n- Experience with API testing tools (Postman, RestAssured)\n- Solid understanding of CI/CD pipelines (GitHub, GitLab)\n- Familiarity with performance and load testing tools\n- Ability to mentor junior QA engineers and embed quality practices\n- Strong analytical and documentation skills','$120,000 - $145,000',13,'2025-08-20 21:06:14','2025-08-23 00:13:34'),(35,'Junior Accountant','Crescent Finance','Abu Dhabi, UAE','Full-time','On-site','Fresher','Finance','As a Junior Accountant, you will support core finance functions such as accounts payable, accounts receivable, reconciliations, and month-end close activities. This entry-level position offers mentorship and growth opportunities into more advanced accounting responsibilities. \n\nYou will work closely with senior accountants to ensure accuracy, compliance, and timely financial reporting while learning best practices in corporate accounting.','- Bachelor’s degree in Accounting, Finance, or related field\n- Strong Excel skills and attention to detail\n- Eagerness to learn and grow within a finance team\n- Ability to handle data entry and reconciliations accurately\n- Familiarity with ERP or accounting software is a plus\n- Strong teamwork and communication abilities\n- English required; Arabic preferred','AED 8,000 - 10,000 / month',14,'2025-08-20 21:06:14','2025-08-23 00:13:34'),(36,'Recruitment Coordinator','NextGen Careers','Remote (US)','Full-time','Remote','Fresher','Other','As a Recruitment Coordinator, you will support the recruiting team by managing candidate logistics and ensuring a smooth hiring process. Your responsibilities will include scheduling interviews, coordinating travel arrangements, preparing offer paperwork, and maintaining accuracy in the applicant tracking system. \n\nThis role is ideal for a detail-oriented individual who enjoys working in a fast-paced environment and wants to learn the fundamentals of recruitment operations while delivering a positive candidate experience.','- 0–1 year of administrative or recruiting support experience\n- Excellent scheduling and multitasking skills\n- Proficiency with Google Workspace or Microsoft Office\n- High attention to detail and organizational ability\n- Friendly communicator with strong problem-solving skills\n- Ability to handle confidential information with professionalism\n- Eagerness to grow into a full-cycle recruiting role','$42,000 - $50,000',15,'2025-08-20 21:06:14','2025-08-23 00:14:46'),(37,'Mobile Engineer (Android)','Innovatech Ltd','Boston, USA','Full-time','Hybrid','Mid-level','IT','As a Mobile Engineer specializing in Android, you will design and develop Kotlin-based applications used by enterprise clients. You will work closely with designers to ensure intuitive, delightful user experiences and collaborate with backend teams to integrate robust APIs. \n\nThis role will challenge you to write clean, maintainable code and contribute to all phases of the mobile development lifecycle, from concept to deployment on the Play Store.','- 3+ years of experience building native Android applications in Kotlin\n- Strong knowledge of MVVM, coroutines, and Jetpack libraries\n- Experience integrating REST and gRPC APIs\n- Proficiency in unit and UI testing frameworks (Espresso, JUnit)\n- Familiarity with Google Play Store deployment\n- Solid understanding of performance optimization for mobile apps\n- Excellent problem-solving and collaboration skills','$100,000 - $125,000',1,'2025-08-20 21:06:14','2025-08-23 00:14:46'),(39,'Clinical Research Associate','MediConnect','San Diego, USA','Contract','Hybrid','Mid-level','Healthcare','As a Clinical Research Associate, you will monitor clinical trial sites to ensure compliance with study protocols, ICH-GCP standards, and regulatory guidelines. You will conduct site visits, review essential documentation, and support investigators in resolving study-related issues. \n\nThis role requires frequent travel and a keen eye for detail to ensure data integrity and patient safety throughout the study lifecycle.','- 3+ years of experience as a CRA in clinical research\n- Strong knowledge of ICH-GCP and FDA/EMA guidelines\n- Ability to manage multiple clinical sites independently\n- Strong documentation and audit readiness skills\n- Excellent organizational and communication abilities\n- Bachelor’s degree in life sciences or related field\n- Willingness to travel 30–50% as required','$95,000 - $110,000',3,'2025-08-20 21:06:14','2025-08-23 00:14:46'),(40,'School Counselor','Bright Future Schools','Valencia, Spain','Full-time','On-site','Mid-level','Education','As a School Counselor, you will provide social-emotional support and guidance to students, partnering with families and teachers to foster student well-being and academic success. You will design and deliver counseling programs, crisis interventions, and preventive workshops tailored to student needs. \n\nThis role requires empathy, discretion, and strong collaboration skills to support a diverse student population across academic and personal challenges.','- Master’s degree in Counseling, Psychology, or related field\n- 2+ years of counseling experience in K–12 settings\n- Fluency in Spanish; professional English proficiency required\n- Training in crisis management and conflict resolution\n- Strong communication and empathy when working with students\n- Ability to maintain confidentiality and handle sensitive matters\n- Familiarity with school counseling frameworks and reporting','€32,000 - €38,000',4,'2025-08-20 21:06:14','2025-08-23 00:14:46'),(41,'Cloud Architect','Apex Solutions','Chicago, USA','Full-time','Hybrid','Senior','IT','As a Cloud Architect, you will design and implement enterprise-grade cloud architectures that emphasize scalability, security, and cost optimization. You will define cloud migration strategies, establish reference architectures, and guide teams in adopting modern cloud practices. \n\nIn this senior role, you will collaborate with executives, engineers, and product teams to shape the company’s long-term cloud vision and enforce governance standards.','- 7+ years of experience in cloud architecture and engineering\n- Expertise in AWS and/or Azure cloud platforms\n- Proficiency with IaC tools (Terraform, CloudFormation)\n- Experience with Kubernetes, containers, and service mesh\n- Strong knowledge of cloud security and cost optimization practices\n- Excellent stakeholder management and presentation skills\n- Cloud certifications (AWS Solutions Architect, Azure Expert) preferred','$160,000 - $190,000',5,'2025-08-20 21:06:14','2025-08-23 00:14:46'),(42,'Treasury Analyst','Euro Finance Group','Paris, France','Full-time','Hybrid','Mid-level','Finance','As a Treasury Analyst, you will manage daily cash positioning, short-term investments, and foreign exchange (FX) hedging. You will work closely with banks and internal stakeholders to optimize liquidity and reduce financial risks. \n\nThis role requires strong analytical skills, attention to detail, and the ability to provide accurate reporting that supports critical business decisions.','- 3+ years of experience in treasury or corporate finance\n- Strong knowledge of cash management and banking systems\n- Proficiency in Excel and financial modeling\n- Familiarity with FX instruments and liquidity strategies\n- Excellent communication and stakeholder collaboration skills\n- Proficiency in English; French is an advantage\n- Strong organizational and problem-solving skills','€48,000 - €60,000',6,'2025-08-20 21:06:14','2025-08-23 00:14:46'),(43,'Nurse Educator','HealthBridge Inc','Phoenix, USA','Full-time','On-site','Senior','Healthcare','As a Nurse Educator, you will design and deliver clinical education programs for nursing staff, including onboarding, competency assessments, and ongoing training. You will collaborate with nurse managers and leadership to ensure staff are equipped with the knowledge and skills needed to provide high-quality patient care. \n\nYou will also evaluate educational outcomes, revise curricula based on best practices, and mentor nurses in developing their professional competencies.','- 5+ years of experience as a Registered Nurse\n- MSN or advanced nursing degree preferred\n- BLS and ACLS instructor certifications\n- Proven experience in curriculum development and teaching\n- Strong communication and leadership skills\n- Ability to mentor and coach nursing staff effectively\n- Data-driven approach to evaluating training outcomes','$95,000 - $115,000',7,'2025-08-20 21:06:14','2025-08-23 00:14:46'),(44,'Curriculum Designer (STEM)','EduWorld Foundation','Ho Chi Minh City, Vietnam','Contract','Remote','Mid-level','Education','As a STEM Curriculum Designer, you will create engaging, project-based learning units that align with multiple curricula. You will collaborate with schools to pilot programs, gather feedback, and refine materials to maximize student engagement and comprehension. \n\nThis role emphasizes innovation, strong content knowledge, and the ability to translate complex STEM concepts into accessible, inquiry-based learning experiences.','- 3+ years of experience designing STEM curricula\n- Strong grasp of inquiry-based and project-based learning\n- Excellent writing, editing, and communication skills\n- Portfolio showcasing curriculum units or assessments\n- Ability to collaborate with teachers and adapt materials for different contexts\n- Fluency in English; additional languages are a plus\n- Comfort with remote collaboration tools and workflows','USD 30 - 40 / hour',8,'2025-08-20 21:06:14','2025-08-23 00:14:46'),(45,'Product Manager (B2B)','BrightTech Solutions','Salt Lake City, USA','Full-time','Hybrid','Mid-level','IT','As a Product Manager for a B2B analytics product, you will lead discovery, prioritization, and delivery of features that drive customer value. You will work closely with engineering and design to ensure the product roadmap aligns with market demands and company strategy. \n\nYou will also analyze customer feedback, run experiments, and measure product success through data-driven metrics. This role requires strong collaboration skills, business acumen, and the ability to influence stakeholders across teams.','- 3–5 years of product management experience, preferably in B2B SaaS\n- Strong discovery and prioritization skills\n- Experience with analytics tools and experimentation frameworks\n- Excellent communication and documentation abilities\n- Ability to balance business needs with technical constraints\n- Proven ability to deliver outcomes in cross-functional teams\n- Familiarity with agile product development practices','$115,000 - $135,000',9,'2025-08-20 21:06:14','2025-08-23 00:14:46'),(46,'People Analytics Lead','FinGrowth Partners','Zurich, Switzerland','Full-time','Hybrid','Senior','Finance','As the People Analytics Lead, you will build and mentor a small team that delivers actionable workforce insights across portfolio companies. You will own the strategy for data acquisition, modeling, and visualization, translating complex people data into recommendations executives can act on. \n\nYou will partner with HRBPs and leadership on topics such as hiring funnels, performance/comp cycles, engagement, attrition, and DEI metrics. You will also establish governance standards to ensure data quality, privacy, and ethical use of employee data across jurisdictions.','- 6+ years in analytics with at least 3 years focused on HR/People data\n- Strong SQL plus proficiency in a BI tool (Tableau, Power BI, or Looker)\n- Experience building dashboards for executives and non-technical stakeholders\n- Ability to define data governance and privacy standards (GDPR/Swiss law awareness)\n- Excellent storytelling with data and C-level communication skills\n- Team leadership and mentoring experience\n- Comfort working in ambiguous, multi-country environments','CHF 120,000 - 140,000',10,'2025-08-20 21:06:14','2025-08-23 00:15:45'),(47,'Medical Assistant','LifeCare Systems','San Mateo, USA','Full-time','On-site','Fresher','Healthcare','As a Medical Assistant, you will provide high-quality support to physicians and nursing staff by preparing patients for exams, taking vitals, and maintaining accurate medical records. You will be a warm first point of contact for patients and families, ensuring an efficient, compassionate experience. \n\nYou will coordinate room turnover, manage supplies, assist with basic procedures, and help patients navigate referrals and follow-ups—all while adhering to privacy and safety protocols.','- Certified Medical Assistant (CMA/RMA) or equivalent training\n- Strong patient-facing communication and empathy\n- EMR proficiency; accurate documentation and charting\n- Organization and attention to detail in fast-paced clinics\n- Knowledge of infection control, OSHA, and vaccine handling\n- Bilingual Spanish/English a plus\n- Reliability, professionalism, and a teamwork mindset','$44,000 - $52,000',11,'2025-08-20 21:06:14','2025-08-23 00:15:45'),(48,'Substitute Teacher','Harmony Academy','New York, USA','Part-time','On-site','Fresher','Education','As a Substitute Teacher, you will provide classroom coverage across elementary grades, following provided lesson plans and maintaining a supportive, structured learning environment. You will quickly build rapport with students, keep classes on track, and communicate effectively with school staff. \n\nYou will manage attendance, behavior, and transitions with clarity and kindness, ensuring continuity of learning when the classroom teacher is absent.','- Bachelor’s degree or enrollment in a teacher preparation program\n- Classroom management fundamentals and positive behavior strategies\n- Clear, patient communication with students and staff\n- Reliability, punctuality, and strong follow-through\n- Ability to adapt quickly to different classrooms and subjects\n- Background check and eligibility to work in schools\n- Desire to support diverse learners','$180 - $220 / day',12,'2025-08-20 21:06:14','2025-08-23 00:15:45'),(49,'Senior Platform Engineer','TechGlobal Inc','Austin, USA','Full-time','Hybrid','Senior','IT','As a Senior Platform Engineer, you will scale shared Kubernetes platforms, service mesh, and developer tooling that power dozens of product teams. You will improve reliability, observability, and golden-path workflows so engineers can ship safely and quickly. \n\nYou will collaborate with SRE, security, and application teams to automate infrastructure, standardize CI/CD, and drive incident response excellence through blameless postmortems and continual improvement.','- 6+ years in platform/SRE/DevOps roles\n- Deep experience with Kubernetes, Helm, and service mesh (Istio/Linkerd)\n- Strong observability stack knowledge and incident response practices\n- Infrastructure-as-code expertise (Terraform) and pipeline automation\n- Cloud proficiency (AWS/GCP/Azure) and Linux fundamentals\n- Clear communication and partner mindset with product teams\n- Experience mentoring engineers and influencing technical direction','$155,000 - $185,000',13,'2025-08-20 21:06:14','2025-08-23 00:15:45'),(50,'Associate Auditor','Crescent Finance','Riyadh, KSA','Full-time','On-site','Junior','Finance','As an Associate Auditor, you will execute risk-based internal audit engagements across business units. You will test controls, document workpapers, and draft clear findings that help leaders strengthen governance, risk management, and compliance. \n\nYou will collaborate with stakeholders to understand processes, identify gaps, and develop practical remediation plans, building a foundation for a career in assurance or risk.','- 1–3 years in internal/external audit or related field\n- Understanding of control frameworks and IFRS/GAAP concepts\n- Strong documentation, independence, and professional skepticism\n- Excellent Excel/PowerPoint; data analysis skills a plus\n- Clear written and verbal communication\n- Progress toward CIA/CPA is advantageous\n- High integrity and discretion with sensitive information','SAR 10,000 - 14,000 / month',14,'2025-08-20 21:06:14','2025-08-23 00:15:45'),(51,'Campus Recruiter','NextGen Careers','Chicago, USA','Full-time','Hybrid','Junior','Other','As a Campus Recruiter, you will plan and execute hiring campaigns across target universities, building strong partnerships with career centers and student groups. You will run info sessions, manage events, and deliver a stellar candidate experience from sourcing to offer. \n\nYou will analyze pipeline data to refine strategies, ensure inclusive hiring practices, and represent the brand with energy and professionalism on campus and online.','- 1–3 years in campus recruiting or early-careers programs\n- Event planning, public speaking, and relationship-building skills\n- Strong organization and follow-through across many stakeholders\n- Data-driven approach using ATS/CRM reporting\n- Excellent written and verbal communication\n- Willingness to travel up to ~20% during peak seasons\n- Passion for inclusive hiring and employer branding','$55,000 - $68,000',15,'2025-08-20 21:06:14','2025-08-23 00:15:45'),(53,'Equity Research Associate','Global Finance Corp','London, UK','Full-time','Hybrid','Junior','Finance','As an Equity Research Associate, you will support senior analysts with financial models, industry research, earnings previews, and client deliverables. You will build deep sector knowledge, maintain coverage models with high data integrity, and contribute to timely notes for investors. \n\nYou will interact with company management teams, synthesize news flow, and help shape investment theses that guide institutional clients.','- 0–2 years in equity research, investment banking, or related finance roles\n- Strong accounting and valuation fundamentals (DCF, comps, precedents)\n- Excel modeling proficiency and PowerPoint polish\n- Clear, concise writing under tight deadlines\n- Intellectual curiosity and attention to detail\n- Progress toward CFA is a plus\n- Professional communication with clients and management teams','£42,000 - £52,000',2,'2025-08-20 21:06:14','2025-08-23 00:15:45'),(54,'Clinical Quality Specialist','MediConnect','Portland, USA','Full-time','Hybrid','Mid-level','Healthcare','As a Clinical Quality Specialist, you will drive quality initiatives across multi-site clinics through audits, training, and continuous improvement. You will partner with operations and nursing leaders to define metrics, close gaps, and strengthen patient safety and outcomes. \n\nYou will prepare documentation for accreditation, coach teams on best practices, and support a culture of learning with data-driven follow-up.','- 3+ years in clinical operations/quality improvement\n- Familiarity with quality metrics, audit tools, and corrective action plans\n- Strong training/facilitation skills and change management mindset\n- Excellent documentation and readiness for regulatory reviews\n- RN/LVN or clinical background preferred\n- Clear communication across clinical and administrative teams\n- Ability to analyze data and present trends to leadership','$82,000 - $98,000',3,'2025-08-20 21:06:14','2025-08-23 00:15:45'),(55,'L&D Specialist','Bright Future Schools','Seville, Spain','Full-time','Hybrid','Mid-level','Education','As a Learning & Development Specialist, you will design and deliver professional development programs for teachers and staff. You will blend workshops, coaching, and e-learning to improve classroom practice and student outcomes. \n\nYou will evaluate program impact with data, iterate on content, and collaborate with school leaders to align PD with instructional priorities and educator needs.','- 3+ years in teacher development, coaching, or L&D\n- Strong facilitation and adult-learning design skills\n- Data-informed approach to program design and evaluation\n- Experience with authoring tools and LMS platforms\n- Spanish and English proficiency required\n- Excellent collaboration and communication skills\n- Portfolio or examples of PD materials preferred','€32,000 - €40,000',4,'2025-08-20 21:06:14','2025-08-23 00:15:45'),(56,'Product Security Engineer','Apex Solutions','Austin, USA','Full-time','Hybrid','Mid-level','IT','As a Product Security Engineer, you will embed with product teams to proactively identify and mitigate security risks. You will threat-model new features, review code and designs, and build guardrails that enable developers to ship secure software without friction. \n\nYou will partner closely with AppSec, platform, and engineering leadership to evolve secure SDLC practices, automate checks in CI/CD, and respond to vulnerabilities with speed and clarity.','- 4+ years in Application/Product Security or related roles\n- Hands-on experience with SAST/DAST, code review, and threat modeling\n- Knowledge of secure SDLC, OWASP Top 10, and common vulns/mitigations\n- Ability to build developer-friendly tooling and guidance\n- Cloud security awareness and modern auth practices (OAuth/OIDC)\n- Effective communicator and partner to engineering teams\n- Comfort balancing risk, velocity, and user impact','$130,000 - $150,000',5,'2025-08-20 21:06:14','2025-08-23 00:15:45'),(57,'3D Environment Artist (Games)','Ubisoft','Montreal, Canada','Full-time','Hybrid','Mid-level','Other','As a 3D Environment Artist, you will craft immersive environments and props for AAA games. You will design detailed scenes that balance realism and artistic intent while ensuring technical performance in real-time engines. \n\nYou will collaborate with level designers, lighting artists, and technical artists to create engaging spaces that enhance gameplay and storytelling. Your work will involve asset optimization, material setup, and maintaining consistency with the project’s visual direction.','- 3+ years as an environment artist in game development\n- Proficiency with Blender or Maya for modeling workflows\n- Strong texturing skills in Substance Painter/Designer\n- Understanding of optimization for real-time engines (Unreal, Unity)\n- Experience with ZBrush for sculpting high-resolution assets\n- Strong portfolio showcasing AAA-quality environments\n- Good communication and ability to work in cross-disciplinary teams','55000-70000 USD',1,'2025-08-22 23:56:13','2025-08-23 00:19:28'),(58,'Junior 3D Artist','Epic Games','Cary, USA','Full-time','On-site','Fresher','Other','As a Junior 3D Artist, you will support senior artists by creating and integrating assets into Unreal projects. This is an excellent entry-level opportunity for artists eager to learn production pipelines in a high-paced, AAA studio environment. \n\nYou will assist with asset cleanup, material setup, and polishing tasks while receiving mentorship to develop professional-grade skills in 3D modeling and texturing.','- 0–2 years of experience in 3D art or strong academic portfolio\n- Familiarity with Blender or Maya for modeling\n- Basic understanding of PBR workflows\n- Portfolio with at least 3 polished works\n- Eagerness to learn from feedback and iterate quickly\n- Strong work ethic and collaboration mindset\n- Familiarity with Unreal Engine integration preferred','40000-50000 USD',2,'2025-08-22 23:56:13','2025-08-23 00:19:28'),(59,'Freelance 3D Prop Artist','ArtStation Marketplace','Remote','Freelance','Remote','Junior','Other','As a Freelance 3D Prop Artist, you will create stylized and realistic props for sale in online marketplaces. This independent role requires self-management and the ability to deliver high-quality assets within agreed deadlines. \n\nYou will build assets that are optimized, clean, and versatile, ensuring they meet the needs of a broad creative audience ranging from indie developers to VFX artists.','- 2+ years of prop modeling experience (professional or freelance)\n- Proficiency in Blender or 3ds Max\n- Strong UV mapping and clean topology practices\n- PBR texturing knowledge (Substance Painter/Designer)\n- Ability to work independently and meet deadlines\n- Strong self-discipline and communication with clients\n- Portfolio with stylized and realistic prop examples','20000-30000 USD',3,'2025-08-22 23:56:13','2025-08-23 00:19:28'),(60,'Senior 3D Artist','Square Enix','Tokyo, Japan','Full-time','On-site','Senior','Other','As a Senior 3D Artist, you will lead asset production for high-profile RPG titles, mentoring junior artists while ensuring the studio’s standards of quality and efficiency are met. You will work closely with art directors to translate concept art into fully realized models. \n\nThis leadership position demands technical mastery, creative excellence, and the ability to deliver polished assets on time for large-scale productions.','- 5+ years of professional 3D art experience in AAA games\n- Strong modeling skills in Maya and ZBrush\n- Advanced texturing expertise using Substance Painter/Designer\n- Experience shipping at least one AAA title\n- Proven mentoring and leadership abilities\n- Knowledge of asset optimization and performance considerations\n- Strong portfolio demonstrating a wide range of asset creation','80000-95000 USD',4,'2025-08-22 23:56:13','2025-08-23 00:19:28'),(61,'3D Generalist Artist','Netflix Animation','Los Angeles, USA','Contract','Hybrid','Mid-level','Other','As a 3D Generalist Artist, you will support animated series and films by contributing to environments, props, and simple FX. This role requires versatility across modeling, texturing, lighting, and rendering, enabling you to work in multiple areas of production. \n\nYou will adapt quickly to shifting priorities and collaborate closely with directors and leads to bring visual concepts to life while maintaining consistency with the project’s style.','- 3+ years of experience as a 3D generalist in film or TV animation\n- Proficiency with Maya or Blender for modeling and animation support\n- Experience with Substance Painter and lighting tools\n- Strong adaptability across disciplines (modeling, texturing, lighting)\n- Good understanding of rendering pipelines\n- Strong communication and teamwork in fast-paced productions\n- Portfolio showing variety of 3D generalist work','65000-75000 USD',5,'2025-08-22 23:56:13','2025-08-23 00:19:28'),(62,'3D Environment Artist','CD Projekt Red','Warsaw, Poland','Full-time','Hybrid','Mid-level','Other','As a 3D Environment Artist, you will design modular kits and large-scale environment sets for open-world RPGs. You will use photogrammetry, procedural techniques, and traditional modeling to create believable environments. \n\nYou will collaborate with quest designers, lighting artists, and tech artists to ensure assets enhance immersion while maintaining visual performance in large, explorable worlds.','- 3+ years as an environment artist in open-world projects\n- Proficiency with modular modeling and set dressing\n- Strong texturing ability with Substance Painter/Designer\n- Experience with photogrammetry workflows\n- Solid optimization knowledge for real-time engines\n- Excellent artistic eye and attention to world-building details\n- Portfolio showcasing open-world environment work','60000-80000 USD',6,'2025-08-22 23:56:13','2025-08-23 00:19:28'),(63,'3D Lighting & Lookdev Artist','Weta FX','Wellington, New Zealand','Full-time','On-site','Senior','Other','As a 3D Lighting & Lookdev Artist, you will light and develop realistic scenes for high-end VFX shots. You will collaborate with surfacing and compositing teams to achieve cinematic results aligned with the project’s visual goals. \n\nYou will be responsible for creating shaders, fine-tuning lighting setups, and ensuring that renders meet the technical and artistic standards of the studio.','- 3+ years of professional experience in lighting/lookdev for film or VFX\n- Expertise with Katana, Maya, or similar tools\n- Strong knowledge of render engines (Arnold, V-Ray, Renderman)\n- Excellent eye for photorealism and cinematic composition\n- Shader creation and look development experience\n- Ability to troubleshoot render and pipeline issues\n- Portfolio demonstrating photoreal lighting and lookdev work','90000-120000 USD',7,'2025-08-22 23:56:13','2025-08-23 00:19:28'),(64,'3D Prop Artist (Realistic)','Rockstar Games','London, UK','Full-time','On-site','Mid-level','Other','As a 3D Prop Artist, you will create high-fidelity props that contribute to immersive storytelling in realistic game worlds. You will apply real-world references and attention to detail to achieve props that show believable wear, tear, and history. \n\nYou will work closely with environment and design teams to integrate props seamlessly into large-scale game environments while optimizing for performance.','- 3+ years of experience as a prop artist in AAA projects\n- Proficiency with Blender or 3ds Max for modeling workflows\n- Strong expertise in Substance Painter for realistic materials\n- Ability to create props from real-world references\n- Knowledge of optimization and LOD workflows\n- Strong understanding of storytelling through environmental assets\n- Portfolio showcasing realistic props with wear and detail','65000-85000 USD',8,'2025-08-22 23:56:13','2025-08-23 00:19:28'),(65,'3D Artist (Environment)','Riot Games','Singapore','Full-time','Hybrid','Mid-level','Other','As an Environment Artist, you will contribute to live titles by building immersive spaces that balance visual style, clarity, and gameplay performance. You will collaborate with game designers to ensure environments support competitive gameplay. \n\nThis role emphasizes teamwork, clear communication, and adaptability as you support ongoing content development for live-service games.','- 3+ years of experience in environment art for live or multiplayer games\n- Strong portfolio demonstrating environment art skills\n- Proficiency with Blender or Maya for modeling\n- Experience optimizing assets for real-time performance\n- Good collaboration skills with designers and engineers\n- Knowledge of Unreal or proprietary game engines\n- Ability to iterate quickly on feedback','60000-78000 USD',9,'2025-08-22 23:56:13','2025-08-23 00:19:28'),(66,'3D Artist (Mobile Games)','Supercell','Helsinki, Finland','Full-time','Hybrid','Fresher','Other','As a 3D Artist for Mobile Games, you will produce assets optimized for mobile devices while maintaining clarity, readability, and strong visual appeal. You will work closely with gameplay teams to design assets that enhance the user experience. \n\nYou will also explore stylized workflows, ensuring assets support the game’s design language and run efficiently across platforms.','- Strong understanding of low-poly modeling workflows\n- 0–2 years of professional experience or strong academic portfolio\n- Familiarity with hand-painted or PBR texturing\n- Willingness to iterate quickly with feedback\n- Proficiency in Blender or Maya for asset creation\n- Understanding of optimization for mobile games\n- Portfolio showcasing mobile-optimized 3D work','45000-55000 USD',10,'2025-08-22 23:56:13','2025-08-23 00:19:28'),(67,'3D Artist (Cinematic)','Blur Studio','Los Angeles, USA','Contract','Remote','Junior','Other','As a 3D Cinematic Artist, you will produce high-quality models and assets for trailers and shorts. You will adapt to shot-specific requirements, ensuring models and materials hold up in close-up renders. \n\nYou will collaborate with lighting and animation teams to ensure assets integrate seamlessly into cinematic productions, with attention to film-quality topology and materials.','- 2+ years of experience in cinematic or film asset creation\n- Strong proficiency with Maya and ZBrush\n- Expertise with Substance Painter and texturing pipelines\n- Knowledge of topology for film-quality models\n- Experience working in VFX or animation pipelines\n- Ability to collaborate with lighting and rendering teams\n- Portfolio showcasing cinematic assets','60000-75000 USD',11,'2025-08-22 23:56:13','2025-08-23 00:19:28'),(68,'3D Artist (AR/VR)','Meta','Dublin, Ireland','Full-time','Hybrid','Mid-level','Other','As a 3D Artist for AR/VR, you will design and develop assets optimized for immersive XR experiences. You will collaborate with developers to ensure assets are performant, visually appealing, and aligned with the interactive nature of AR/VR platforms. \n\nThis role will require you to balance aesthetics with strict optimization constraints, pushing the boundaries of immersive storytelling.','- 3+ years of experience in AR/VR asset development\n- Proficiency in Unity or Unreal Engine\n- Strong understanding of PBR workflows and performance profiling\n- Ability to create lightweight assets without sacrificing quality\n- Familiarity with immersive design principles for AR/VR\n- Strong portfolio showing AR/VR-ready assets\n- Collaborative approach with developers and UX designers','70000-90000 USD',12,'2025-08-22 23:56:13','2025-08-23 00:19:28'),(69,'3D Generalist (Indie)','Noodlestorm Studios','Remote','Part-time','Remote','Junior','Other','As a 3D Generalist in an indie studio, you will wear multiple hats across modeling, texturing, and simple rigging. You will contribute to a variety of tasks while working closely with a small, tight-knit team. \n\nThis role requires flexibility, problem-solving skills, and strong communication to bring creative visions to life with limited resources.','- 2+ years of experience in generalist roles or indie projects\n- Strong modeling and texturing skills using Blender and Substance Painter\n- Basic rigging and animation knowledge\n- Ability to adapt to multiple art tasks\n- Strong communication and collaboration in small teams\n- Self-motivated and organized with indie production constraints\n- Portfolio demonstrating versatility in 3D work','25000-40000 USD',13,'2025-08-22 23:56:13','2025-08-23 00:19:28'),(70,'Hard-Surface 3D Artist','Respawn Entertainment','Los Angeles, USA','Full-time','On-site','Senior','Other','As a Hard-Surface 3D Artist, you will create hero assets such as weapons, vehicles, and machinery for action-oriented titles. You will focus on producing high-quality, production-ready models that emphasize precision, functionality, and aesthetic appeal. \n\nYou will collaborate with design and animation teams to ensure assets not only look great but also function seamlessly in gameplay.','- 4+ years of professional hard-surface modeling experience\n- Expert knowledge of Blender, Maya, or 3ds Max\n- Strong experience with trim sheets, decals, and optimization workflows\n- Shipped at least one title preferred\n- Strong understanding of mechanical design and surface detail\n- Excellent texturing ability with Substance tools\n- Portfolio showcasing AAA-quality hard-surface assets','90000-115000 USD',14,'2025-08-22 23:56:13','2025-08-23 00:19:28'),(71,'3D Environment Artist (Stylized)','miHoYo','Shanghai, China','Full-time','Hybrid','Mid-level','Other','As a Stylized Environment Artist, you will design and produce vibrant, visually appealing environments that align with the unique art style of miHoYo games. You will focus on strong shape language, color harmony, and stylized material creation. \n\nYou will collaborate with concept artists, tech artists, and designers to ensure environments achieve a perfect balance of playability and artistic vision.','- 3+ years of experience in stylized environment art\n- Strong portfolio of stylized environments and props\n- Proficiency with Blender or Maya for modeling\n- Substance Painter/Designer skills for stylized material creation\n- Strong understanding of color and shape language\n- Ability to work with concept art and translate it into 3D\n- Excellent collaboration and iteration skills with design teams','60000-80000 USD',15,'2025-08-22 23:56:13','2025-08-23 00:19:28');
